#include <BMx280I2C.h>
#define I2C_ADDRESS 0x76
BMx280I2C bmx280(I2C_ADDRESS);
void setup() {
  Wire.begin();
  bmx280.begin();
  bmx280.resetToDefaults();
  bmx280.writeOversamplingPressure(BMx280MI::OSRS_P_x16);
  bmx280.writeOversamplingTemperature(BMx280MI::OSRS_T_x16);
  if (bmx280.isBME280())
    bmx280.writeOversamplingHumidity(BMx280MI::OSRS_H_x16);
}

void loop() {
  bmx280.measure();
  do {
    delay(100);
  } while (!bmx280.hasValue());
  Serial.print("Pressione: "); Serial.println(bmx280.getPressure());
  Serial.print("Temp: "); Serial.println(bmx280.getTemperature());
  if (bmx280.isBME280()) {
    Serial.print("Umidità: "); Serial.println(bmx280.getHumidity());
  }
  delay(1000);
}

#include <Stepper.h>
const int stepsPerRevolution = 200;
Stepper myStepper(stepsPerRevolution, 8, 10, 9, 11); // ordine ULN2003!
void setup() {
  myStepper.setSpeed(30); // RPM
  myStepper.step(200);   // un giro orario
  delay(500);
  myStepper.step(-200);  // un giro antiorario
}

void loop() {
  int sensorReading = analogRead(A0);
  int motorSpeed = map(sensorReading, 0, 1023, 0, 100);
  if (motorSpeed > 0) {
    myStepper.setSpeed(motorSpeed);
    myStepper.step(1); // avanza 1 passo per loop
  }
}

// Formula: OCR2A = (F_CPU / (prescaler * freq_hz)) - 1
// 16MHz / (256 * 100Hz) - 1 = 624
// Per 200 Hz (60 RPM): OCR2A = 311, OCR2B = 155
// Per 50 Hz (15 RPM): OCR2A = 1249 (troppo > 255!) → usare prescaler 1024
OCR2A = 624;
OCR2B = OCR2A / 2; // duty 50% sempre
